  uint32_t SHIFTEIEN;                              /**< Shifter Error Interrupt Enable, offset: 0x24 */
  uint32_t TIMIEN;                                 /**< Timer Interrupt Enable Register, offset: 0x28 */
  uint8_t RESERVED_1[4];
