/*!
 * @addtogroup TPM_Peripheral TPM
 * @{
 */

/** TPM - Peripheral register structure */
typedef struct TPM_MemMap {
  uint32_t VERID;                                  /**< Version ID Register, offset: 0x0 */
  uint32_t PARAM;                                  /**< Parameter Register, offset: 0x4 */
  uint32_t GLOBAL;                                 /**< TPM Global Register, offset: 0x8 */
  uint8_t RESERVED_0[4];
  uint32_t SC;                                     /**< Status and Control, offset: 0x10 */
  uint32_t CNT;                                    /**< Counter, offset: 0x14 */
  uint32_t MOD;                                    /**< Modulo, offset: 0x18 */
  uint32_t STATUS;                                 /**< Capture and Compare Status, offset: 0x1C */
  struct {                                         /* offset: 0x20, array step: 0x8 */
    uint32_t CnSC;                                   /**< Channel (n) Status and Control, array offset: 0x20, array step: 0x8 */
    uint32_t CnV;                                    /**< Channel (n) Value, array offset: 0x24, array step: 0x8 */
  } CONTROLS[6];
  uint8_t RESERVED_1[20];
  uint32_t COMBINE;                                /**< Combine Channel Register, offset: 0x64 */
  uint8_t RESERVED_2[4];
  uint32_t TRIG;                                   /**< Channel Trigger, offset: 0x6C */
  uint32_t POL;                                    /**< Channel Polarity, offset: 0x70 */
  uint8_t RESERVED_3[4];
  uint32_t FILTER;                                 /**< Filter Control, offset: 0x78 */
  uint8_t RESERVED_4[4];
  uint32_t QDCTRL;                                 /**< Quadrature Decoder Control and Status, offset: 0x80 */
  uint32_t CONF;                                   /**< Configuration, offset: 0x84 */
} volatile *TPM_MemMapPtr;

